/**
 * TodoList — Generated by Elmoorx AI Copilot
 * Reactive todo list with filters and persistence.
 */

import { $store, $effect, h } from "@elmoorx/runtime";

const TodoList = () => {
  const store = $store({
    todos: [],
    text: "",
    filter: "all",
    nextId: 1,
  });

  $effect(() => {
    const saved = localStorage.getItem("elmoorx-todos");
    if (saved) {
      const parsed = JSON.parse(saved);
      store.todos = parsed.todos || [];
      store.nextId = parsed.nextId || 1;
    }
  });

  const addTodo = () => {
    const text = store.text.trim();
    if (!text) return;
    store.todos.push({ id: store.nextId, text, done: false });
    store.nextId += 1;
    store.text = "";
  };

  const toggle = (id) => {
    const todo = store.todos.find((t) => t.id === id);
    if (todo) todo.done = !todo.done;
  };

  const remove = (id) => {
    const i = store.todos.findIndex((t) => t.id === id);
    if (i >= 0) store.todos.splice(i, 1);
  };

  const filtered = () => {
    if (store.filter === "active") return store.todos.filter(t => !t.done);
    if (store.filter === "completed") return store.todos.filter(t => t.done);
    return store.todos;
  };

  const remaining = () => store.todos.filter(t => !t.done).length;

  return h("div", { class: "todo-app" },
    h("h1", null, "Todos"),
    h("div", { class: "input-row" },
      h("input", { type: "text", placeholder: "What needs to be done?",
        value: () => store.text,
        onInput: (e) => store.text = e.target.value,
        onKeyDown: (e) => { if (e.key === "Enter") addTodo(); }
      }),
      h("button", { onClick: addTodo }, "Add")
    ),
    h("div", { class: "filters" },
      ["all", "active", "completed"].map((f) =>
        h("button", { class: store.filter === f ? "active" : "",
          onClick: () => store.filter = f
        }, f)
      )
    ),
    h("ul", null,
      () => filtered().map((todo) =>
        h("li", { class: todo.done ? "done" : "" },
          h("input", { type: "checkbox", checked: todo.done,
            onChange: () => toggle(todo.id) }),
          h("span", null, todo.text),
          h("button", { onClick: () => remove(todo.id) }, "×")
        )
      )
    ),
    h("div", { class: "footer" },
      () => `${remaining()} of ${store.todos.length} remaining`
    )
  );
};

export default function Page() {
  return h("main", null, TodoList());
}
